import{_ as t,o as n,c as i,a3 as r}from"./chunks/framework.CjquFG0V.js";const g=JSON.parse('{"title":"94. Trainee Enrolled Nurses","description":"","frontmatter":{"title":"94. Trainee Enrolled Nurses","eba":"Nurses and Midwives 2024-2028","topics":["staffing"]},"headers":[],"relativePath":"ebas/nurses-midwives/classification-staffing/94-trainee-enrolled-nurses.md","filePath":"ebas/nurses-midwives/classification-staffing/94-trainee-enrolled-nurses.md"}'),a={name:"ebas/nurses-midwives/classification-staffing/94-trainee-enrolled-nurses.md"};function o(s,e,l,p,h,d){return n(),i("div",null,[...e[0]||(e[0]=[r('<h1 id="_94-trainee-enrolled-nurses" tabindex="-1">94. Trainee Enrolled Nurses <a class="header-anchor" href="#_94-trainee-enrolled-nurses" aria-label="Permalink to &quot;94. Trainee Enrolled Nurses&quot;">​</a></h1><p><strong>94.1</strong> Application</p><p><strong>(a)</strong> This clause applies only to the employment of a Trainee Enrolled Nurse undertaking a Diploma of Nursing in Traineeship mode where that Trainee at any time during their Training Contract forms part of a Local Agreement under the Safe Patient Care Act.</p><p><strong>(b)</strong> A Trainee who is initially engaged to be supernumerary at all times during their Training Contract, but subsequently forms part of a Local Agreement under the Safe Patient Care Act will for the entirety of their Training Contract be treated as a Trainee in accordance with this clause.</p><p>Example: A Trainee engaged under the YES program who was intended to be totally supernumerary for the duration of their Training Contract is subsequently utilised</p><p>by the Employer to meet the Local Agreement under the Safe Patient Care Act when this was not anticipated at the commencement of the Training Contract.</p><p><strong>94.2</strong> Definitions</p><p><strong>(a)</strong> Approved Training means that training which is specified in the Training Plan which is part of the Training Agreement registered with the relevant State or Territory Training Authority. It includes training undertaken both on and off-the- job in a Traineeship and involves formal instruction, both theoretical and practical, and supervised practice. The training reflects the requirements of a National Training Package or a Traineeship Scheme and leads to a qualification under the Australian Qualification Framework.</p><p><strong>(b)</strong> Trainee is an individual who is a signatory to a training agreement registered with the relevant Victorian Training Authority and is involved in paid work and structured training which may be on or off the job. &quot;Trainee&quot; does not include an individual who already has the competencies to which the traineeship is directed.</p><p><strong>(c)</strong> Traineeship means a system of training which has been approved by the relevant Victorian Training Authority, or which meets the requirements of a National Training Package developed by a National Industry Training Advisory Board and endorsed by the National Training Framework Committee, which leads to an Australian Qualifications Framework qualification specified by that National Training Package, and includes full-time traineeships and part-time traineeships including school-based traineeships.</p><p><strong>(d)</strong> Training Agreement means an agreement for a Traineeship made between an Employer and a trainee which is registered with the relevant Victorian Training Authority.</p><p><strong>94.3</strong> Training Conditions</p><p><strong>(a)</strong> The Employer will provide a Registered Nurse mentor to each Trainee during the traineeship period.</p><p><strong>(b)</strong> The Employer will ensure that there is appropriate nurse education support available to those Trainees.</p><p><strong>94.4</strong> Employment Arrangements</p><p><strong>(a)</strong> A Trainee Enrolled Nurse who immediately prior to commencing the traineeship was an existing Employee of the Employer will, in the event their Traineeship is terminated by the Employer for other than serious and wilful misconduct, revert to their pre-traineeship position.</p><p><strong>(b)</strong> Where the employment of a Trainee by an Employer is continued after the completion of the traineeship period, such employment period will be counted as service for the purposes of this Agreement or any other legislative entitlement.</p><p><strong>94.5</strong> Employment Conditions for Trainees</p><p><strong>(a)</strong> The rates of pay for a Trainee Enrolled Nurse engaged pursuant to this clause will be in accordance with Part I – Wages of <a href="/eba/ebas/nurses-midwives/appendices/02-wages-and-allowances.html">Appendix 2</a>, and will be the basis for the calculation of overtime and/or weekend rates prescribed by this Agreement.</p><p><strong>(b)</strong> A Trainee, whether full-time or part-time, will be permitted to be absent from work to attend clinical placements without loss of weekly salary or diminution of accrued leave entitlements.</p><p><strong>(c)</strong> All the terms and conditions of this Agreement that are applicable to an Enrolled Nurse will apply unless specifically varied by this clause.</p><p><strong>(d)</strong> A Trainee will not be on call during the period of their Training Contract.</p><p><strong>94.6</strong> Limitations</p><p><strong>(a)</strong> A Trainee Enrolled Nurse will be rostered so as to provide an 8 hour break before and after attending Approved Training or clinical placement.</p><p><strong>(b)</strong> Trainee positions are additional to existing positions. No existing Employee will lose employment as a result of the introduction of Trainees. An Employer will not dispense with the services of Employees for the purposes of appointing a Trainee before or after that appointment.</p><p><strong>(c)</strong> Where the Trainee completes the qualification in the Training Contract to the satisfaction of the Nursing and Midwifery Board of Australia earlier than the time specified in the Training Contract then the Trainee will be considered a full Enrolled Nurse for the purposes of the Agreement terms and conditions for the duration of the Training Contract.</p><p>Plain language terms: TEN, trainee EN.</p>',27)])])}const u=t(a,[["render",o]]);export{g as __pageData,u as default};
